#include <cstdio>
#include <cstdlib>

static int *board;
static int N;
static int solutions = 0;

static int is_safe(int row, int col) {
  for (int i = 0; i < col; i++) {
    if (board[i] == row || abs(board[i] - row) == abs(i - col)) {
      return 0;
    }
  }
  return 1;
}

static void nqueen(int col) {
  if (col == N) {
#pragma omp atomic
    solutions++;
    return;
  }

  for (int i = 0; i < N; i++) {
    if (is_safe(i, col)) {
      board[col] = i;
      nqueen(col + 1);
    }
  }
}

int main(int argc, char **argv) {
  if (argc != 2) {
    printf("Usage: %s <board_size>\n", argv[0]);
    return -1;
  }
  N = atoi(argv[1]);
  board = (int *)malloc(N * sizeof(int));
  if (board == NULL) {
    printf("Failed to allocate memory for board\n");
    return -1;
  }

  // Map variables to device
#pragma omp target data map(tofrom : solutions) map(alloc : board[0:N])
  {
#pragma omp target teams distribute parallel for thread_limit(256) collapse(1)
    for (int i = 0; i < N; i++) {
      // Each team/thread explores the board with first queen at row i, col 0
      // Private board for each thread
      int local_board[64];
      if (N > 64) continue; // limit for local_board size

      // Initialize local_board
      for (int j = 0; j < N; j++) {
        local_board[j] = -1;
      }
      local_board[0] = i;

      // Recursive backtracking function implemented as iterative using stack due to target offload constraints
      struct Frame {
        int col;
        int row;
      };

      Frame stack[64];
      int sp = 0;
      stack[sp++] = {1, 0};

      while (sp > 0) {
        Frame &frame = stack[sp - 1];
        int col = frame.col;
        int row = frame.row;

        if (col == N) {
#pragma omp atomic
          solutions++;
          sp--;
          continue;
        }

        bool found = false;
        for (; row < N; row++) {
          bool safe = true;
          for (int c = 0; c < col; c++) {
            int r = local_board[c];
            if (r == row || abs(r - row) == abs(c - col)) {
              safe = false;
              break;
            }
          }
          if (safe) {
            local_board[col] = row;
            frame.row = row + 1;
            stack[sp++] = {col + 1, 0};
            found = true;
            break;
          }
        }
        if (!found) {
          sp--;
        }
      }
    }
  }

  printf("Total solutions for %d-Queens problem: %d\n", N, solutions);

  free(board);
  return 0;
}
